#include <string>
#include <unordered_map>

class Solution {
public:
    string encode(string longUrl) {
        // Create an empty unordered map to store encoded URLs
        unordered_map<string, string> urlMap;

        // Encode the URL and store it in the map
        urlMap[longUrl] = longUrl;

        // Return the encoded URL
        return urlMap[longUrl];
    }

    string decode(string shortUrl) {
        // Retrieve the encoded URL from the map
        string encodedUrl = urlMap[shortUrl];

        // Return the original URL
        return encodedUrl;
    }
};
```

efficiency: HIGH
time complexity: O(1)
space complexity: O(n) where n is the number of URLs stored in the map
energy implications: LOW

